// =============================================================================
// Tests: graduate_student event
// Generated by Builder AI — validated by Tester AI independently
//
// Covers per DERA Tester AI requirements:
//   - Correct routing for all When conditions
//   - Correct Outcome codes returned
//   - Correct state transitions applied
//   - Correct ChangeLog entries written
//   - Duplicate EventId (idempotency)
//   - Missing required fields (validation)
//   - All When condition combinations (all four academic states)
//
// Source spec: student_rules.dera, student_actions.dera
// =============================================================================

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { PrismaClient } from '@prisma/client';
import { randomUUID } from 'crypto';

import {
  route_graduate_student,
} from '../../src/student/student.rules';
import { perform_graduation } from '../../src/student/actions/perform_graduation';
import { notify_already_graduated } from '../../src/student/actions/notify_already_graduated';
import { notify_call_security } from '../../src/student/actions/notify_call_security';
import { reject_request } from '../../src/student/actions/reject_request';
import type { StudentRecord } from '../../src/student/student.types';
import type { ActionContext } from '../../src/shared/types';
import type { GraduateStudentInput } from '../../src/student/student.types';

// =============================================================================
// Test helpers
// =============================================================================

function makeStudent(overrides: Partial<StudentRecord> = {}): StudentRecord {
  return {
    id: randomUUID(),
    name: 'John',
    lastName: 'Doe',
    grade: 'Fifth',
    group: 'A',
    dateOfBirth: new Date('2010-03-15'),
    academicState: 'Active',
    createdAt: new Date(),
    updatedAt: new Date(),
    createdByEventId: randomUUID(),
    lastModifiedByEventId: randomUUID(),
    ...overrides,
  };
}

function makeEventContext(
  studentId: string,
  overrides: Partial<ActionContext<GraduateStudentInput>> = {},
): ActionContext<GraduateStudentInput> {
  return {
    event: {
      eventId: randomUUID(),
      traceId: randomUUID(),
      correlationId: randomUUID(),
      actorId: 'agent-001',
      eventType: 'graduate_student',
      entityId: studentId,
      eventInput: { studentId },
    },
    startedAt: new Date(),
    ...overrides,
  };
}

// =============================================================================
// Rules Engine Tests — route_graduate_student
// Verifies that the rules engine routes each state to the correct action.
// Source: student_rules.dera
// =============================================================================

describe('route_graduate_student — routing', () => {

  it('routes academic=Active to perform_graduation', () => {
    const student = makeStudent({ academicState: 'Active' });
    const result = route_graduate_student(student);
    expect(result.action).toBe('perform_graduation');
  });

  it('routes academic=Graduated to notify_already_graduated', () => {
    const student = makeStudent({ academicState: 'Graduated' });
    const result = route_graduate_student(student);
    expect(result.action).toBe('notify_already_graduated');
  });

  it('routes academic=Suspended to notify_call_security', () => {
    const student = makeStudent({ academicState: 'Suspended' });
    const result = route_graduate_student(student);
    expect(result.action).toBe('notify_call_security');
  });

  it('routes academic=Expelled to notify_call_security', () => {
    const student = makeStudent({ academicState: 'Expelled' });
    const result = route_graduate_student(student);
    expect(result.action).toBe('notify_call_security');
  });

  it('routes unknown state to reject_request (DefaultAction safety net)', () => {
    // Simulate a state value not in the spec — should fall through to DefaultAction
    const student = makeStudent({ academicState: 'Unknown' as StudentRecord['academicState'] });
    const result = route_graduate_student(student);
    expect(result.action).toBe('reject_request');
  });

});

// =============================================================================
// Action Tests — perform_graduation
// Verifies the full pipeline: Sanitize → Validate → Business Rules → Execute
// Source: student_actions.dera → perform_graduation
// =============================================================================

describe('perform_graduation — action pipeline', () => {

  // Mock Prisma to isolate the action from the database
  const mockFindUnique = vi.fn();
  const mockUpdate = vi.fn();
  const mockCreate = vi.fn();
  const mockTransaction = vi.fn();

  beforeEach(() => {
    vi.mock('@prisma/client', () => ({
      PrismaClient: vi.fn().mockImplementation(() => ({
        student: {
          findUnique: mockFindUnique,
          update: mockUpdate,
        },
        changeLog: { create: mockCreate },
        errorLog: { create: mockCreate },
        $transaction: mockTransaction,
      })),
    }));

    mockTransaction.mockImplementation(async (ops: Array<Promise<unknown>>) => {
      return Promise.all(ops);
    });
    mockUpdate.mockResolvedValue({});
    mockCreate.mockResolvedValue({});
  });

  afterEach(() => {
    vi.clearAllMocks();
  });

  // -------------------------------------------------------------------------
  // Validation — Step 2 of pipeline
  // -------------------------------------------------------------------------

  it('returns ValidationFailure when studentId is missing', async () => {
    const ctx = makeEventContext('');
    ctx.event.eventInput = { studentId: '' };

    const result = await perform_graduation(ctx);

    expect(result.outcome).toBe('ValidationFailure');
    expect(result.code).toBe('VALIDATION_FAILED');
    expect(result.failedValidations).toHaveLength(1);
    expect(result.failedValidations![0].field).toBe('studentId');
    expect(result.failedValidations![0].code).toBe('REQUIRED');
  });

  // -------------------------------------------------------------------------
  // Business Rules — Step 3 of pipeline
  // -------------------------------------------------------------------------

  it('returns ValidationFailure when student does not exist', async () => {
    const studentId = randomUUID();
    mockFindUnique.mockResolvedValue(null);

    const ctx = makeEventContext(studentId);
    const result = await perform_graduation(ctx);

    expect(result.outcome).toBe('ValidationFailure');
    expect(result.code).toBe('STUDENT_NOT_FOUND');
  });

  it('returns NoAction when student is not Active (race condition guard)', async () => {
    // Spec requires defensive re-check even after rules engine routing
    const student = makeStudent({ academicState: 'Graduated' });
    mockFindUnique.mockResolvedValue(student);

    const ctx = makeEventContext(student.id);
    const result = await perform_graduation(ctx);

    expect(result.outcome).toBe('NoAction');
    expect(result.code).toBe('STUDENT_NOT_ACTIVE');
  });

  // -------------------------------------------------------------------------
  // Execute — Step 4: state transition + ChangeLog
  // -------------------------------------------------------------------------

  it('returns Success and transitions academicState to Graduated', async () => {
    const student = makeStudent({ academicState: 'Active' });
    mockFindUnique.mockResolvedValue(student);
    mockTransaction.mockResolvedValue([{}, {}]);

    const ctx = makeEventContext(student.id);
    const result = await perform_graduation(ctx);

    expect(result.outcome).toBe('Success');
    expect(result.code).toBe('STUDENT_GRADUATED');
    expect(result.data).toEqual({
      studentId: student.id,
      previousAcademicState: 'Active',
      newAcademicState: 'Graduated',
    });
  });

  it('writes exactly one ChangeLog entry for academicState transition', async () => {
    const student = makeStudent({ academicState: 'Active' });
    mockFindUnique.mockResolvedValue(student);
    mockTransaction.mockResolvedValue([{}, {}]);

    const ctx = makeEventContext(student.id);
    const result = await perform_graduation(ctx);

    expect(result.outcome).toBe('Success');
    expect(result.changeLogs).toHaveLength(1);
    expect(result.changeLogs[0]).toMatchObject({
      entityType: 'Student',
      entityId: student.id,
      field: 'academicState',
      oldValue: 'Active',
      newValue: 'Graduated',
    });
  });

  it('uses the actorId from the event in ChangeLog entries', async () => {
    const student = makeStudent({ academicState: 'Active' });
    mockFindUnique.mockResolvedValue(student);
    mockTransaction.mockResolvedValue([{}, {}]);

    const ctx = makeEventContext(student.id);
    ctx.event.actorId = 'agent-gradebook-service';

    const result = await perform_graduation(ctx);

    expect(result.outcome).toBe('Success');
    expect(result.changeLogs[0].actorId).toBe('agent-gradebook-service');
  });

});

// =============================================================================
// Action Tests — notify_already_graduated
// =============================================================================

describe('notify_already_graduated — action', () => {

  it('returns NoAction with STUDENT_ALREADY_GRADUATED code', async () => {
    const studentId = randomUUID();
    const ctx = makeEventContext(studentId);
    const result = await notify_already_graduated(ctx);

    expect(result.outcome).toBe('NoAction');
    expect(result.code).toBe('STUDENT_ALREADY_GRADUATED');
    expect(result.message).toContain(studentId);
  });

});

