// =============================================================================
// Idempotency — same EventId must return stored result without re-executing
// Covered at the route level (student.routes.ts checkIdempotency)
// These tests verify the contract from the rules engine perspective:
// the action should be callable once and produce a deterministic result.
// =============================================================================

describe('graduate_student — deterministic execution', () => {

  const mockFindUnique = vi.fn();
  const mockTransaction = vi.fn();

  beforeEach(() => {
    vi.mock('@prisma/client', () => ({
      PrismaClient: vi.fn().mockImplementation(() => ({
        student: { findUnique: mockFindUnique },
        changeLog: { create: vi.fn() },
        errorLog: { create: vi.fn() },
        $transaction: mockTransaction,
      })),
    }));
    mockTransaction.mockResolvedValue([{}, {}]);
  });

  afterEach(() => vi.clearAllMocks());

  it('produces the same result on repeated calls with the same input and state', async () => {
    const student = makeStudent({ academicState: 'Active' });
    mockFindUnique.mockResolvedValue(student);

    const eventId = randomUUID();
    const ctx = makeEventContext(student.id);
    ctx.event.eventId = eventId;

    const result1 = await perform_graduation(ctx);
    // Reset mock to simulate same state (idempotency guard is at route level)
    mockFindUnique.mockResolvedValue(student);
    const result2 = await perform_graduation(ctx);

    expect(result1.outcome).toBe(result2.outcome);
    expect(result1.code).toBe(result2.code);
    expect(result1.data).toEqual(result2.data);
  });

});
